import { Command, type CommandDefinition } from '../utils/command.js';
import type { CLIOptions, CommandResult, CommandContext, ProjectSnapshot } from '../types/index.js';
import { existsSync, readFileSync, readdirSync, lstatSync } from 'fs';
import { join, relative } from 'path';
import { printTable } from '../utils/output.js';
import { createHash } from 'crypto';

export class DiffCommand extends Command {
  // ... (definition remains same)
  readonly definition: CommandDefinition = {
    name: 'diff',
    description: 'Compare snapshot against local filesystem',
    usage: 'jref diff [options] [file.json]',
    options: [
      {
        flags: '--directory, -d <dir>',
        description: 'Target directory to compare against (default: current directory)'
      },
      {
        flags: '--all, -a',
        description: 'Include local files that are missing from the snapshot'
      }
    ],
    examples: [
      'jref diff snapshot.json',
      'jref diff --directory ./another-project snapshot.json',
      'jref diff --all snapshot.json'
    ],
    workflows: [
      'Integrity Check: Verify if the local project files match exactly what is in the snapshot.',
      'Change Detection: Identify modifications made to local files since the snapshot was created.',
      'Missing File Audit: Use --all to find files present locally that were not captured in the snapshot.'
    ]
  };

  async execute(
    args: string[],
    options: CLIOptions,
    context: CommandContext
  ): Promise<CommandResult> {
    try {
      const { flags, snapshotFile } = this.parseArgs(args);
      const targetDir = (flags.directory as string) || process.cwd();

      let snapshot: ProjectSnapshot;
      if (context.snapshot) {
        snapshot = context.snapshot;
      } else if (snapshotFile) {
        const { loadSnapshotFromFile } = await import('../utils/streaming-json.js');
        snapshot = await loadSnapshotFromFile(snapshotFile, options);
      } else {
        const { loadSnapshot } = await import('../utils/streaming-json.js');
        snapshot = await loadSnapshot(context.stdin, options);
      }

      const modifiedFiles: { path: string; isBinary: boolean; oldSize?: number; newSize?: number }[] = [];
      const missingFiles: string[] = [];
      const extraFiles: string[] = [];
      const encodings = snapshot.encodings || {};

      // 1. Check files from snapshot
      for (const [filePath, content] of Object.entries(snapshot.files)) {
        const localPath = join(targetDir, filePath);
        const isBinary = encodings[filePath] === 'base64';

        if (!existsSync(localPath)) {
          missingFiles.push(filePath);
        } else if (lstatSync(localPath).isDirectory()) {
          // Path in snapshot is a file, but on disk is a directory (unlikely but possible)
          missingFiles.push(filePath);
        } else {
          if (isBinary) {
            const localBuffer = readFileSync(localPath);
            const snapshotBuffer = Buffer.from(content, 'base64');

            if (localBuffer.length !== snapshotBuffer.length || this.computeHash(localBuffer) !== this.computeHash(snapshotBuffer)) {
              modifiedFiles.push({ path: filePath, isBinary: true, oldSize: snapshotBuffer.length, newSize: localBuffer.length });
            }
          } else {
            const localContent = readFileSync(localPath, 'utf8');
            if (localContent !== content) {
              modifiedFiles.push({ path: filePath, isBinary: false });
            }
          }
        }
      }

      // 2. Check for extra local files
      if (flags.all) {
          this.findExtraFiles(targetDir, snapshot.files, extraFiles);
      }

      const result = {
        modifiedFiles,
        missingFiles,
        extraFiles,
        targetDir
      };

      if (options.json) {
        const output = JSON.stringify(result, null, 2);
        return this.success(output);
      } else {
        this.printHumanDiff(result, options);
        return this.success();
      }

    } catch (err) {
      return this.error(`Diff failed: ${(err as Error).message}`, options);
    }
  }

  private computeHash(buffer: Buffer): string {
    return createHash('sha256').update(buffer).digest('hex');
  }

  private findExtraFiles(dir: string, snapshotFiles: Record<string, string>, extraFiles: string[], baseDir?: string): void {
    const root = baseDir || dir;
    const entries = readdirSync(dir);

    for (const entry of entries) {
      const fullPath = join(dir, entry);
      const relativePath = relative(root, fullPath);

      // Basic ignore list (should use .gitignore later)
      if (entry === '.git' || entry === 'node_modules' || entry === 'dist') continue;

      if (lstatSync(fullPath).isDirectory()) {
        this.findExtraFiles(fullPath, snapshotFiles, extraFiles, root);
      } else if (snapshotFiles[relativePath] === undefined) {
        extraFiles.push(relativePath);
      }
    }
  }

  private printHumanDiff(result: any, options: CLIOptions): void {
    console.log(`\nрџ”Ќ DIFFING SNAPSHOT VS ${result.targetDir}`);
    console.log('в”Ђ'.repeat(50));

    const tableData: string[][] = [];

    for (const f of result.modifiedFiles) {
      if (f.isBinary) {
        tableData.push(['M (bin)', `${f.path} (${this.formatBytes(f.oldSize!)} -> ${this.formatBytes(f.newSize!)})`]);
      } else {
        tableData.push(['M', f.path]);
      }
    }
    for (const f of result.missingFiles) tableData.push(['A', f + ' (missing locally)']);
    for (const f of result.extraFiles) tableData.push(['D', f + ' (not in snapshot)']);

    if (tableData.length === 0) {
      console.log('вњ… No differences found');
    } else {
      printTable(['Status', 'Path'], tableData, options);
    }
    console.log();
  }

  private formatBytes(bytes: number): string {
    if (bytes === 0) return '0 B';
    const k = 1024;
    const sizes = ['B', 'KB', 'MB', 'GB'];
    const i = Math.floor(Math.log(bytes) / Math.log(k));
    return `${parseFloat((bytes / Math.pow(k, i)).toFixed(1))} ${sizes[i]}`;
  }

  protected parseArgs(args: string[]): { flags: Record<string, unknown>; snapshotFile?: string } {
    const flags: Record<string, unknown> = {};
    let snapshotFile: string | undefined;

    for (let i = 0; i < args.length; i++) {
      const arg = args[i];
      if (arg === '--directory' || arg === '-d') {
        flags.directory = args[++i];
      } else if (arg === '--all' || arg === '-a') {
        flags.all = true;
      } else if (!arg.startsWith('-')) {
        snapshotFile = arg;
      }
    }

    return { flags, snapshotFile };
  }
}

