/**
 * Extract Command
 * Unpack specific files, directories, or entire project back into local filesystem
 * Supports streaming for large snapshots and wildcard pattern matching
 */

import { Command, type CommandDefinition } from '../utils/command.js';
import type {
  CLIOptions,
  CommandResult,
  CommandContext
} from '../types/index.js';
import { processSnapshot } from '../utils/streaming-json.js';
import { mkdir, writeFile, existsSync, createReadStream, readFileSync, statSync } from 'fs';
import { join, dirname } from 'path';
import { promisify } from 'util';
import { Readable } from 'stream';
import micromatch from 'micromatch';
import { decodeBase64 } from '../utils/binary.js';
import * as readline from 'readline';

const mkdirAsync = promisify(mkdir);
const writeFileAsync = promisify(writeFile);

interface ExtractFlags {
  outputDir?: string;
  patterns?: string[];
  overwrite?: boolean;
  dryRun?: boolean;
  flat?: boolean;
  stdout?: boolean;
  listen?: boolean;
}

export class ExtractCommand extends Command {
  readonly definition: CommandDefinition = {
    name: 'extract',
    description: 'Unpack files from snapshot to local filesystem',
    usage: 'jref extract [options] [file] [patterns...]',
    options: [
      {
        flags: '--output, -o <dir>',
        description: 'Target directory for extraction (default: ./extracted)'
      },
      {
        flags: '--overwrite, -w',
        description: 'Overwrite existing files'
      },
      {
        flags: '--dry-run',
        description: 'Show what would be extracted without writing to disk'
      },
      {
        flags: '--flat',
        description: 'Extract files directly into output dir, ignoring subfolder structure'
      },
      {
        flags: '--stdout',
        description: 'Pipes a single decoded asset directly to stdout'
      },
      {
        flags: '--listen',
        description: 'Listen on stdin for continuous stream of snapshots/deltas'
      }
    ],
    examples: [
      'jref extract snapshot.json',
      'jref extract snapshot.json "src/**/*.ts"',
      'jref extract --output ./output snapshot.json',
      'cat snapshot.json | jref extract "src/*.js"',
      'jref extract --dry-run snapshot.json',
      'jref extract --stdout snapshot.json "kick.wav" | ./dsp_tool',
      'jref extract --listen'
    ],
    workflows: [
      'Full Reconstruction: Extract an entire snapshot to restore a project.',
      'Selective Extraction: Use glob patterns to extract only specific modules or files.',
      'Conflict Prevention: Use --dry-run to verify extraction paths before committing changes.',
      'Structure Flattening: Use --flat to gather scattered files into a single directory for processing.',
      'Real-time Mirroring: Use --listen to receive and apply continuous updates from a stream.'
    ]
  };

  async execute(
    args: string[],
    options: CLIOptions,
    context: CommandContext
  ): Promise<CommandResult> {
    try {
      const { flags, filePath } = this.parseArgs(args, context);
      const patterns = flags.patterns || [];

      // Determine output directory
      const outputDir = flags.outputDir as string || './extracted';

      if (flags.listen) {
        if (!options.silent) {
          console.error(`рџ‘‚ Listening for snapshots on stdin (Output: ${outputDir})...`);
        }
        await this.handleListen(outputDir, flags, options);
        return this.success();
      }

      // Handle --stdout piping
      if (flags.stdout) {
        if (patterns.length === 0) {
          return this.error('--stdout requires at least one file pattern', options);
        }

        options.silent = true;
        let pipedBuffer: Buffer | null = null;
        let pipedPath: string | null = null;
        const encodings: Record<string, string> = {};

        const onFilePipe = async (path: string, content: string) => {
          if (pipedBuffer) return;
          const isMatch = micromatch.isMatch(path, patterns);
          if (!isMatch) return;

          // We found a match, but we might not know the encoding yet.
          // Store it as a string for now, and we'll decode at the end.
          pipedPath = path;
          pipedBuffer = Buffer.from(content, 'utf8'); // Store raw string as buffer for now
        };

        if (options.jq) {
          const snapshot = await this.getSnapshot(context, options, filePath);
          const snapshotEncodings = snapshot.encodings || {};
          const file = Object.entries(snapshot.files).find(([path]) => micromatch.isMatch(path, patterns));
          if (file) {
            const [path, content] = file;
            const encoding = snapshotEncodings[path] || 'utf8';
            const buffer = encoding === 'base64' ? decodeBase64(content as string) : Buffer.from(content as string, 'utf8');
            process.stdout.write(buffer);
            return this.success();
          }
        } else {
          let input: string | NodeJS.ReadableStream;
          if (filePath) {
            input = createReadStream(filePath);
          } else {
            input = context.stdinIsPipe ? Readable.from([context.stdin!]) : process.stdin;
          }

          await processSnapshot(input, {
            onMetadata: (key, value) => {
              if (key === 'encodings') Object.assign(encodings, value);
            },
            onFile: onFilePipe
          });

          if (pipedBuffer && pipedPath) {
            const encoding = encodings[pipedPath] || 'utf8';
            const content = (pipedBuffer as Buffer).toString('utf8');
            const finalBuffer = encoding === 'base64' ? decodeBase64(content) : Buffer.from(content, 'utf8');
            process.stdout.write(finalBuffer);
            return this.success();
          }
        }

        return this.error('No files matched the patterns for piping', { ...options, silent: false });
      }

      const results: { path: string; size: number; success: boolean; skipped?: boolean }[] = [];
      const encodings: Record<string, string> = {};

      if (options.jq) {
        // Use full loading when JQ is active
        const snapshot = await this.getSnapshot(context, options, filePath);
        const snapshotEncodings = snapshot.encodings || {};
        for (const [path, content] of Object.entries(snapshot.files)) {
          // Check if path matches patterns (wildcard or directory prefix)
          const isMatch = patterns.length === 0 || 
                          micromatch.isMatch(path, patterns) ||
                          patterns.some(p => path.startsWith(p.endsWith('/') ? p : p + '/'));

          if (!isMatch) continue;

          const encoding = snapshotEncodings[path] || 'utf8';
          const buffer = encoding === 'base64' ? decodeBase64(content as string) : Buffer.from(content as string, 'utf8');

          if (flags.dryRun) {
            results.push({ path: path, size: buffer.length, success: true });
            continue;
          }

          // Perform extraction
          const res = await this.extractFile(path, buffer, outputDir, flags.overwrite as boolean, flags.flat as boolean);
          results.push(res);
        }
      } else {
        // Determine if we should read fully or stream
        let input: string | NodeJS.ReadableStream;
        if (filePath) {
          const stats = statSync(filePath);
          if (stats.size < 8 * 1024 * 1024) { // 8MB
            input = readFileSync(filePath, 'utf8');
          } else {
            input = createReadStream(filePath);
          }
        } else {
          input = context.stdinIsPipe ? Readable.from([context.stdin!]) : process.stdin;
        }

        // Use streaming processor to avoid OOM
        await processSnapshot(input, {
            onMetadata: (key, value) => {
              if (key === 'encodings') {
                Object.assign(encodings, value);
              }
            },
            onFile: async (path, content) => {
              // Check if path matches patterns (wildcard or directory prefix)
              const isMatch = patterns.length === 0 || 
                              micromatch.isMatch(path, patterns) ||
                              patterns.some(p => path.startsWith(p.endsWith('/') ? p : p + '/'));

              if (!isMatch) return;

              const encoding = encodings[path] || 'utf8';
              const buffer = encoding === 'base64' ? decodeBase64(content) : Buffer.from(content, 'utf8');

              if (flags.dryRun) {
                results.push({ path: path, size: buffer.length, success: true });
                return;
              }

              // Perform extraction
              const res = await this.extractFile(path, buffer, outputDir, flags.overwrite as boolean, flags.flat as boolean);
              results.push(res);
            }
          }
        );
      }

      if (results.length === 0) {
        return this.error('No files matched the patterns or snapshot is empty', options);
      }

      // Output results
      if (flags.dryRun) {
        this.outputDryRun(results, outputDir, flags.flat as boolean, options);
      } else {
        this.outputResults(results, options);
      }

      return this.success();
    } catch (err) {
      return this.error(`Extract failed: ${(err as Error).message}`, options);
    }
  }

  protected parseArgs(args: string[], context?: CommandContext): { flags: ExtractFlags; filePath?: string } {
    const flags: ExtractFlags = {};
    let filePath: string | undefined;
    const patterns: string[] = [];

    const isPipe = context?.stdinIsPipe || false;

    for (let i = 0; i < args.length; i++) {
      const arg = args[i];
      switch (arg) {
        case '--output':
        case '-o':
          flags.outputDir = args[++i];
          break;
        case '--overwrite':
        case '-w':
          flags.overwrite = true;
          break;
        case '--dry-run':
          flags.dryRun = true;
          break;
        case '--flat':
          flags.flat = true;
          break;
        case '--stdout':
          flags.stdout = true;
          break;
        case '--listen':
          flags.listen = true;
          break;
        case '--paths':
        case '-p':
          // Support old --paths flag for backward compatibility
          while (i + 1 < args.length && !args[i + 1].startsWith('-')) {
              patterns.push(args[++i]);
          }
          break;
        default:
          if (!arg.startsWith('-')) {
            if (!filePath && !isPipe) {
              filePath = arg;
            } else {
              patterns.push(arg);
            }
          }
      }
    }

    flags.patterns = patterns;
    return { flags, filePath };
  }

  private async handleListen(outputDir: string, flags: ExtractFlags, options: CLIOptions): Promise<void> {
    const rl = readline.createInterface({
      input: process.stdin,
      terminal: false
    });

    let currentPayloadStream: Readable | null = null;
    let pushToPayload: ((chunk: string) => void) | null = null;
    const processingPromises: Promise<void>[] = [];

    for await (const line of rl) {
      if (line.trim() === '--JREF-START--') {
        currentPayloadStream = new Readable({
          read() {}
        });

        const stream = currentPayloadStream;
        pushToPayload = (chunk: string) => {
          stream.push(chunk + '\n');
        };

        // Start processing the stream
        const p = this.processProtocolStream(stream, outputDir, flags, options).catch(err => {
          if (!options.silent) console.error(`вќЊ Stream processing error: ${err.message}`);
        });
        processingPromises.push(p);
        continue;
      }

      if (line.trim() === '--JREF-END--') {
        if (currentPayloadStream) {
          currentPayloadStream.push(null); // End of stream
          currentPayloadStream = null;
          pushToPayload = null;
        }
        continue;
      }

      if (pushToPayload) {
        pushToPayload(line);
      }
    }

    // Wait for all chunks to be processed
    await Promise.all(processingPromises);
  }

  private async processProtocolStream(stream: Readable, outputDir: string, flags: ExtractFlags, options: CLIOptions): Promise<void> {
    const encodings: Record<string, string> = {};
    const results: { path: string; size: number; success: boolean; skipped?: boolean }[] = [];
    const patterns = flags.patterns || [];

    await processSnapshot(stream, {
      onMetadata: (key, value) => {
        if (key === 'encodings') {
          Object.assign(encodings, value);
        } else if (key === 'type' && !options.silent) {
          console.error(`рџ“¦ Received protocol chunk: ${value}`);
        }
      },
      onFile: async (path, content) => {
        const isMatch = patterns.length === 0 || 
                        micromatch.isMatch(path, patterns) ||
                        patterns.some(p => path.startsWith(p.endsWith('/') ? p : p + '/'));

        if (!isMatch) return;

        const encoding = encodings[path] || 'utf8';
        const buffer = encoding === 'base64' ? decodeBase64(content) : Buffer.from(content, 'utf8');

        // Always overwrite in listen mode
        const res = await this.extractFile(path, buffer, outputDir, true, flags.flat as boolean);
        results.push(res);
      }
    });

    if (!options.silent && results.length > 0) {
      console.error(`вњ… Applied update: ${results.length} files extracted.`);
    }
  }

  private async extractFile(
    filePath: string,
    content: string | Buffer,
    outputDir: string,
    overwrite: boolean,
    flat: boolean | undefined
  ): Promise<{ path: string; size: number; success: boolean; skipped?: boolean }> {
    let outputPath: string;
    if (flat) {
      outputPath = join(outputDir, filePath.split('/').pop()!);
    } else {
      outputPath = join(outputDir, filePath);
    }

    try {
      // Check if file exists (unless overwrite)
      if (!overwrite && existsSync(outputPath)) {
        return { path: outputPath, size: 0, success: false, skipped: true };
      }

      // Create parent directories
      const parentDir = dirname(outputPath);
      if (!existsSync(parentDir)) {
        await mkdirAsync(parentDir, { recursive: true });
      }

      // Write file
      await writeFileAsync(outputPath, content);

      return {
        path: outputPath,
        size: Buffer.isBuffer(content) ? content.length : Buffer.byteLength(content as string, 'utf8'),
        success: true
      };
    } catch (err) {
      return { path: outputPath, size: 0, success: false };
    }
  }

  private outputDryRun(
    results: { path: string; size: number }[],
    outputDir: string,
    flat: boolean | undefined,
    options: CLIOptions
  ): void {
    if (options.json) {
      this.print({ files: results.map(r => r.path), outputDir, flat, action: 'dry-run' }, options);
      return;
    }

    console.log('\nрџ”Ќ DRY RUN - Files that would be extracted:\n');
    for (const r of results) {
      console.log(`  ${r.path} (${this.formatBytes(r.size)})`);
    }
    console.log(`\nTotal: ${results.length} file(s)`);
    console.log(`Output directory: ${outputDir}`);
    console.log();
  }

  private outputResults(
    results: { path: string; size: number; success: boolean; skipped?: boolean }[],
    options: CLIOptions
  ): void {
    const successful = results.filter((r) => r.success);
    const skipped = results.filter((r) => r.skipped);
    const failed = results.filter((r) => !r.success && !r.skipped);

    if (options.json) {
      this.print({
        total: results.length,
        successful: successful.length,
        skipped: skipped.length,
        failed: failed.length,
        files: results
      }, options);
      return;
    }

    console.log('\nрџ“¦ EXTRACTION RESULTS\n');

    if (successful.length > 0) {
      console.log(`вњ… Successfully extracted ${successful.length} file(s):`);
      // Show first 10 files if too many
      const showCount = Math.min(successful.length, 20);
      for (let i = 0; i < showCount; i++) {
        console.log(`   ${successful[i].path} (${this.formatBytes(successful[i].size)})`);
      }
      if (successful.length > showCount) {
        console.log(`   ... and ${successful.length - showCount} more`);
      }
    }

    if (skipped.length > 0) {
      console.log(`\nвЏ­пёЏ  Skipped ${skipped.length} existing file(s) (use --overwrite to replace)`);
    }

    if (failed.length > 0) {
      console.log(`\nвќЊ Failed to extract ${failed.length} file(s):`);
      for (const r of failed) {
        console.log(`   ${r.path}`);
      }
    }

    console.log();
  }

  private formatBytes(bytes: number): string {
    if (bytes === 0) return '0 B';
    const k = 1024;
    const sizes = ['B', 'KB', 'MB', 'GB'];
    const i = Math.floor(Math.log(bytes) / Math.log(k));
    return `${parseFloat((bytes / Math.pow(k, i)).toFixed(1))} ${sizes[i]}`;
  }
}

