/**
 * TUI Components for Interactive Snapshot Browser
 * Built with Ink (React for CLI) - using programmatic API instead of JSX
 */

import React, { useState } from 'react';
import { Box, Text, useInput } from 'ink';
import type { TreeNode } from '../utils/ui.js';
import { exec, spawnSync } from 'child_process';
import { writeFileSync, readFileSync, mkdirSync, existsSync } from 'fs';
import { join, dirname } from 'path';
import { tmpdir } from 'os';
import Fuse from 'fuse.js';
import { GraphSnapshot } from '../types/index.js';

interface SnapshotBrowserProps {
  tree: TreeNode;
  files: Record<string, string>;
  encodings: Record<string, string>;
  graph?: GraphSnapshot;
  onExit: () => void;
}

// Tree item for flattened view
interface FlatTreeItem {
  node: TreeNode;
  depth: number;
  isExpanded: boolean;
}

// Export for testing
export function buildFlatTree(root: TreeNode, expanded: Set<string>): FlatTreeItem[] {
  const items: FlatTreeItem[] = [];

  // Detect structure: single-container (typical project) vs multi-root (monorepo/workspace)
  const singleContainer = root.children.length === 1 && root.children[0].isDirectory;
  const containerPath = singleContainer ? root.children[0].path : '';

  function traverse(node: TreeNode, depth: number) {
    // Compute the path used for file lookup and expansion state
    let nodePath: string;
    if (node === root) {
      nodePath = ''; // dummy root
    } else if (singleContainer && node.path.startsWith(containerPath + '/')) {
      // Strip container prefix (e.g., "project/src" -> "src")
      nodePath = node.path.slice(containerPath.length + 1);
    } else if (singleContainer && node.path === containerPath) {
      // The container itself
      nodePath = '';
    } else {
      // Multi-root or other: use full path as-is
      nodePath = node.path;
    }

    // Add non-root nodes to flat list
    if (node !== root) {
      items.push({
        node: {
          ...node,
          path: nodePath
        },
        depth: depth - 1, // Adjust depth so first visible level is at depth 0
        isExpanded: expanded.has(nodePath)
      });
    }

    // Traverse children if this directory is expanded (always traverse dummy root)
    const shouldTraverse = node === root
      ? true
      : node.isDirectory && expanded.has(nodePath);

    if (shouldTraverse) {
      for (const child of node.children) {
        traverse(child, depth + 1);
      }
    }
  }

  traverse(root, 0);
  return items;
}

export function SnapshotBrowser({ tree, files, encodings, graph, onExit }: SnapshotBrowserProps) {
  const [selectedIndex, setSelectedIndex] = useState(0);
  const [viewMode, setViewMode] = useState<'tree' | 'file' | 'search' | 'graph'>('tree');
  const [selectedFile, setSelectedFile] = useState<string | null>(null);
  const [scrollOffset, setScrollOffset] = useState(0);
  const [searchQuery, setSearchQuery] = useState('');
  const [searchType, setSearchType] = useState<'filename' | 'content'>('filename');
  const [searchResults, setSearchResults] = useState<string[]>([]);
  const [isCompactMode, setIsCompactMode] = useState(false);
  const [statusMessage, setStatusMessage] = useState<string | null>(null);
  // Initialize expanded directories - include project root (using relative paths)
  const [expandedDirs, setExpandedDirs] = useState<Set<string>>(new Set(['']));
  const [selectedPaths, setSelectedPaths] = useState<Set<string>>(new Set());

  // Graph Subgraph memo
  const relevantEdges = React.useMemo(() => {
    if (!graph || !selectedFile) return [];
    return graph.edges.filter(e => e.source === selectedFile || e.target === selectedFile);
  }, [graph, selectedFile]);

  // Toggle directory expansion
  const toggleExpansion = React.useCallback((nodePath: string) => {
    setExpandedDirs(prev => {
      const newSet = new Set(prev);
      if (newSet.has(nodePath)) {
        newSet.delete(nodePath);
      } else {
        newSet.add(nodePath);
      }
      return newSet;
    });
  }, []);

  // Toggle path selection
  const toggleSelection = React.useCallback((nodePath: string) => {
    setSelectedPaths(prev => {
      const newSet = new Set(prev);
      if (newSet.has(nodePath)) {
        newSet.delete(nodePath);
      } else {
        newSet.add(nodePath);
      }
      return newSet;
    });
  }, []);

  // Compute flat tree directly (avoid useEffect timing issues)
  const flatTreeItems = React.useMemo(() => {
    return buildFlatTree(tree, expandedDirs);
  }, [tree, expandedDirs]);

  // Fuzzy Search instance
  const fuse = React.useMemo(() => {
    const allFiles = Object.keys(files);
    if (searchType === 'filename') {
      return new Fuse(allFiles, {
        threshold: 0.4,
        distance: 100,
      });
    } else {
      const data = allFiles.map(path => ({ path, content: files[path] }));
      return new Fuse(data, {
        keys: ['content'],
        threshold: 0.4,
        distance: 1000,
      });
    }
  }, [files, searchType]);

  // Adjust selected index if it's out of bounds
  React.useEffect(() => {
    if (selectedIndex >= flatTreeItems.length) {
      setSelectedIndex(Math.max(0, flatTreeItems.length - 1));
    }
  }, [flatTreeItems.length, selectedIndex]);

  // Detect screen size and set compact mode
  React.useEffect(() => {
    const checkScreenSize = () => {
      try {
        // Get terminal dimensions
        const { columns = 80 } = process.stdout;
        setIsCompactMode(columns < 60); // Compact mode for narrow screens
      } catch {
        setIsCompactMode(false);
      }
    };

    checkScreenSize();
    // Check on resize if available
    const resizeHandler = () => checkScreenSize();
    process.stdout.on?.('resize', resizeHandler);
    return () => {
      process.stdout.off?.('resize', resizeHandler);
    };
  }, []);

  // Helper functions for mobile-friendly display
  const truncatePath = (path: string, maxLength: number = isCompactMode ? 20 : 40): string => {
    if (path.length <= maxLength) return path;
    return '...' + path.slice(-(maxLength - 3));
  };

  const getFileName = (path: string): string => {
    return path.split('/').pop() || path;
  };

  const formatBytes = (bytes: number): string => {
    if (bytes === 0) return '0 B';
    const k = 1024;
    const sizes = ['B', 'KB', 'MB', 'GB'];
    const i = Math.floor(Math.log(bytes) / Math.log(k));
    return `${parseFloat((bytes / Math.pow(k, i)).toFixed(1))} ${sizes[i]}`;
  };

  const showStatus = (msg: string) => {
    setStatusMessage(msg);
    setTimeout(() => setStatusMessage(null), 2000);
  };

  // Update search results when query changes
  const updateSearchResults = React.useCallback((query: string) => {
    if (!query.trim()) {
      setSearchResults([]);
      return;
    }

    const results = fuse.search(query);
    if (searchType === 'filename') {
      setSearchResults(results.map(r => r.item as string));
    } else {
      setSearchResults(results.map(r => (r.item as { path: string }).path));
    }
  }, [fuse, searchType]);

  // Handle keyboard input
  useInput((input, key) => {
    if (key.escape) {
      if (viewMode === 'search' || viewMode === 'graph') {
        setViewMode('tree');
        setSearchQuery('');
        setSearchResults([]);
        setSelectedIndex(0);
      } else if (viewMode === 'file') {
        setViewMode('tree');
        setSelectedFile(null);
        setScrollOffset(0);
      } else {
        onExit();
      }
      return;
    }

    if (viewMode === 'tree') {
      const visibleLines = isCompactMode ? 15 : 20;

      if (input === ' ' && !key.ctrl) {
        const selectedItem = flatTreeItems[selectedIndex];
        if (selectedItem) {
          toggleSelection(selectedItem.node.path);
        }
        return;
      }

      if (input === 'y' && !key.ctrl) {
        const selectedItem = flatTreeItems[selectedIndex];
        if (selectedItem && !selectedItem.node.isDirectory) {
          const content = files[selectedItem.node.path];
          if (content) {
            const isTermux = process.env.TERMUX_VERSION !== undefined;
            const command = isTermux ? 'termux-clipboard-set' : (process.platform === 'darwin' ? 'pbcopy' : 'xclip -selection clipboard');
            const child = exec(command);
            child.stdin?.write(content);
            child.stdin?.end();
            showStatus('Yanked to clipboard');
          }
        }
        return;
      }

      if (input === 'e' && !key.ctrl) {
        const selectedItem = flatTreeItems[selectedIndex];
        if (selectedItem && !selectedItem.node.isDirectory) {
          const content = files[selectedItem.node.path];
          if (content !== undefined) {
            const tempPath = join(tmpdir(), `jref-${Date.now()}-${selectedItem.node.name}`);
            writeFileSync(tempPath, content);
            spawnSync(process.env.EDITOR || 'vi', [tempPath], { stdio: 'inherit' });
            const updatedContent = readFileSync(tempPath, 'utf8');
            files[selectedItem.node.path] = updatedContent;
            showStatus('File edited (in-memory)');
          }
        }
        return;
      }

      if (input === 'v' && !key.ctrl) {
        const selectedItem = flatTreeItems[selectedIndex];
        if (selectedItem && !selectedItem.node.isDirectory) {
          const content = files[selectedItem.node.path];
          if (content !== undefined) {
            const tempPath = join(tmpdir(), `jref-view-${Date.now()}-${selectedItem.node.name}`);
            writeFileSync(tempPath, content);
            const pager = process.env.JREF_PAGER || process.env.PAGER || 'less';
            spawnSync(pager, [tempPath], { stdio: 'inherit' });
            showStatus('Closed pager');
          }
        }
        return;
      }

      if (input === 'x' && !key.ctrl) {
        const extractFile = (path: string, content: string) => {
          const outputPath = join(process.cwd(), path);
          const parentDir = dirname(outputPath);
          if (!existsSync(parentDir)) {
            mkdirSync(parentDir, { recursive: true });
          }
          writeFileSync(outputPath, content);
        };

        if (selectedPaths.size > 0) {
          let count = 0;
          selectedPaths.forEach(path => {
            const content = files[path];
            if (content !== undefined) {
              extractFile(path, content);
              count++;
            }
          });
          showStatus(`Extracted ${count} files`);
          setSelectedPaths(new Set());
        } else {
          const selectedItem = flatTreeItems[selectedIndex];
          if (selectedItem && !selectedItem.node.isDirectory) {
            const content = files[selectedItem.node.path];
            if (content !== undefined) {
              extractFile(selectedItem.node.path, content);
              showStatus(`Extracted: ${selectedItem.node.name}`);
            }
          }
        }
        return;
      }

      if (input === '/' && !key.ctrl) {
        setViewMode('search');
        setSearchQuery('');
        setSearchResults([]);
        setSelectedIndex(0);
        return;
      }

      if (input === 'c' && !key.ctrl) {
        // Toggle compact mode
        setIsCompactMode(!isCompactMode);
        return;
      }

      if (input === 'g' && !key.ctrl) {
        const selectedItem = flatTreeItems[selectedIndex];
        if (selectedItem) {
          setSelectedFile(selectedItem.node.path);
          setViewMode('graph');
          setSelectedIndex(0);
        }
        return;
      }

      if (key.upArrow || input === 'k') {
        const newIndex = Math.max(0, selectedIndex - 1);
        setSelectedIndex(newIndex);
        // Adjust scroll to keep selected item visible
        if (newIndex < scrollOffset) {
          setScrollOffset(newIndex);
        }
      } else if (key.downArrow || input === 'j') {
        const newIndex = Math.min(Math.max(0, flatTreeItems.length - 1), selectedIndex + 1);
        setSelectedIndex(newIndex);
        // Adjust scroll to keep selected item visible
        if (newIndex >= scrollOffset + visibleLines) {
          setScrollOffset(newIndex - visibleLines + 1);
        }
      } else if (key.return) {
        const selectedItem = flatTreeItems[selectedIndex];
        if (selectedItem) {
          if (selectedItem.node.isDirectory) {
            toggleExpansion(selectedItem.node.path);
          } else {
            // Show file content
            setSelectedFile(selectedItem.node.path);
            setViewMode('file');
            setScrollOffset(0);
          }
        }
      } else if (key.leftArrow || input === 'h') {
        // Collapse directory
        const selectedItem = flatTreeItems[selectedIndex];
        if (selectedItem && selectedItem.node.isDirectory && expandedDirs.has(selectedItem.node.path)) {
          toggleExpansion(selectedItem.node.path);
        }
      } else if (key.rightArrow || input === 'l') {
        // Expand directory
        const selectedItem = flatTreeItems[selectedIndex];
        if (selectedItem && selectedItem.node.isDirectory && !expandedDirs.has(selectedItem.node.path)) {
          toggleExpansion(selectedItem.node.path);
        }
      }
    } else if (viewMode === 'search') {
      if (key.return) {
        // Select the current search result
        if (searchResults[selectedIndex]) {
          setSelectedFile(searchResults[selectedIndex]);
          setViewMode('file');
          setScrollOffset(0);
        }
      } else if (key.tab) {
        // Toggle search type
        const newType = searchType === 'filename' ? 'content' : 'filename';
        setSearchType(newType);
        updateSearchResults(searchQuery);
      } else if (key.backspace || key.delete) {
        const newQuery = searchQuery.slice(0, -1);
        setSearchQuery(newQuery);
        updateSearchResults(newQuery);
        setSelectedIndex(0);
      } else if (input && !key.ctrl && !key.meta) {
        const newQuery = searchQuery + input;
        setSearchQuery(newQuery);
        updateSearchResults(newQuery);
        setSelectedIndex(0);
      } else if (key.upArrow) {
        setSelectedIndex(Math.max(0, selectedIndex - 1));
      } else if (key.downArrow) {
        setSelectedIndex(Math.min(searchResults.length - 1, selectedIndex + 1));
      }
    } else if (viewMode === 'file') {
       if (key.return || input === 'q' || key.escape) {
          setViewMode('tree');
          setSelectedFile(null);
          setScrollOffset(0);
          return;
       }

       const isBinary = encodings[selectedFile!] === 'base64';
       if (isBinary) return; // Binary view is static

       const lines = (selectedFile ? files[selectedFile] : '').split('\n');
       const visibleLines = isCompactMode ? 15 : 20;
       const maxScroll = Math.max(0, lines.length - visibleLines);

       if (input === 'y' && !key.ctrl) {
          if (selectedFile) {
            const content = files[selectedFile];
            const isTermux = process.env.TERMUX_VERSION !== undefined;
            const command = isTermux ? 'termux-clipboard-set' : (process.platform === 'darwin' ? 'pbcopy' : 'xclip -selection clipboard');
            const child = exec(command);
            child.stdin?.write(content);
            child.stdin?.end();
            showStatus('Yanked to clipboard');
          }
          return;
       }

       if (key.upArrow) {
         setScrollOffset(Math.max(0, scrollOffset - 1));
       } else if (key.downArrow) {
         setScrollOffset(Math.min(maxScroll, scrollOffset + 1));
       } else if (key.pageUp) {
         setScrollOffset(Math.max(0, scrollOffset - visibleLines));
       } else if (key.pageDown) {
         setScrollOffset(Math.min(maxScroll, scrollOffset + visibleLines));
       }
    }
  });

  if (viewMode === 'graph' && selectedFile) {
    const fileName = getFileName(selectedFile);
    return React.createElement(Box, { flexDirection: 'column', height: '100%' }, [
      React.createElement(Box, { key: 'header', borderStyle: 'round', borderColor: 'cyan', paddingX: 1 },
        React.createElement(Text, { color: 'cyan', bold: true }, `рџ”— KNOWLEDGE GRAPH: ${fileName}`)
      ),
      React.createElement(Box, { key: 'instr', paddingX: 1 },
        React.createElement(Text, { color: 'yellow', dimColor: true }, 'Esc Back вЂў в†‘в†“ Navigate')
      ),
      React.createElement(Box, { key: 'content', flexDirection: 'column', flexGrow: 1, paddingX: 1, borderStyle: 'single', borderColor: 'gray' },
        relevantEdges.length === 0 
          ? React.createElement(Text, { color: 'gray', italic: true }, 'No relationships found in graph.')
          : relevantEdges.map((edge, idx) => {
              const isSource = edge.source === selectedFile;
              const otherId = isSource ? edge.target : edge.source;
              const direction = isSource ? 'в”Ђв”Ђв–¶' : 'в—Ђв”Ђв”Ђ';
              const color = isSource ? 'green' : 'blue';

              return React.createElement(Box, { key: idx },
                React.createElement(Text, { color }, [
                  isSource ? 'self' : otherId,
                  ` ${direction} (${edge.relation}) ${direction} `,
                  isSource ? otherId : 'self'
                ])
              );
            })
      )
    ]);
  }

  if (viewMode === 'file' && selectedFile) {
    const isBinary = encodings[selectedFile] === 'base64';
    const fileName = getFileName(selectedFile);

    if (isBinary) {
      const decodedSize = Buffer.byteLength(files[selectedFile], 'base64');
      return React.createElement(Box, { flexDirection: 'column', height: '100%' }, [
        React.createElement(Box, { key: 'header', borderStyle: 'round', borderColor: 'magenta', paddingX: 1 },
          React.createElement(Text, { color: 'magenta', bold: true }, `рџ“¦ BINARY ASSET: ${selectedFile}`)
        ),
        React.createElement(Box, { key: 'content', flexGrow: 1, alignItems: 'center', justifyContent: 'center', borderStyle: 'single', borderColor: 'gray' },
          React.createElement(Box, { flexDirection: 'column', alignItems: 'center' }, [
            React.createElement(Text, { key: 'msg', color: 'yellow', bold: true }, '[ Binary Data Placeholder ]'),
            React.createElement(Text, { key: 'name', color: 'white' }, `Filename: ${fileName}`),
            React.createElement(Text, { key: 'size', color: 'cyan' }, `Decoded Size: ${formatBytes(decodedSize)}`),
            React.createElement(Box, { key: 'pad', marginY: 1 }),
            React.createElement(Text, { key: 'hint', color: 'gray', dimColor: true }, 'Rendering Base64 strings is disabled to maintain performance.'),
            React.createElement(Text, { key: 'esc', color: 'green' }, 'Press any key to return')
          ])
        )
      ]);
    }

    const content = files[selectedFile] || 'File not found';
    const lines = content.split('\n');
    const visibleLinesCount = isCompactMode ? 15 : 20;
    const slicedLines = lines.slice(scrollOffset, scrollOffset + visibleLinesCount);
    const headerText = isCompactMode
      ? `${fileName} (${lines.length})`
      : `рџ“„ ${truncatePath(selectedFile)} (${lines.length} lines)`;

    return React.createElement(Box, { flexDirection: 'column', height: '100%' }, [
      // Header
      React.createElement(Box, { key: 'header', borderStyle: isCompactMode ? 'single' : 'round', borderColor: 'green', paddingX: isCompactMode ? 0 : 1 },
        React.createElement(Text, { color: 'green', bold: true }, headerText)
      ),

      // Instructions
      !isCompactMode ? React.createElement(Box, { key: 'instructions', paddingX: 1, paddingY: 0 },
        React.createElement(Text, { color: 'yellow', dimColor: true }, 'в†‘в†“ Scroll вЂў Esc Back вЂў y Yank')
      ) : null,

      // Status Bar
      statusMessage ? React.createElement(Box, { key: 'status', paddingX: 1 },
        React.createElement(Text, { color: 'green', bold: true }, `вњЁ ${statusMessage}`)
      ) : null,

      // Content
      React.createElement(Box, { key: 'content', flexDirection: 'column', flexGrow: 1, paddingX: isCompactMode ? 0 : 1 },
        slicedLines.map((line, index) => {
          const lineNum = scrollOffset + index + 1;
          const lineNumText = isCompactMode
            ? lineNum.toString().padStart(2, ' ')
            : lineNum.toString().padStart(4, ' ');

          return React.createElement(Text, { key: scrollOffset + index, color: 'white' }, [
            React.createElement(Text, { key: 'line-num', color: 'gray', dimColor: true },
              lineNumText + (isCompactMode ? '' : ':')
            ),
            isCompactMode ? '' : ' ',
            line || ' '
          ]);
        }).concat(lines.length > visibleLinesCount ? [
          React.createElement(Box, { key: 'scroll-info', paddingTop: 1 },
            React.createElement(Text, { color: 'gray', dimColor: true },
              isCompactMode
                ? `${scrollOffset + 1}-${Math.min(scrollOffset + visibleLinesCount, lines.length)}/${lines.length}`
                : `Lines ${scrollOffset + 1}-${Math.min(scrollOffset + visibleLinesCount, lines.length)} of ${lines.length}`
            )
          )
        ] : [])
      )
    ].filter(Boolean));
  }

  if (viewMode === 'search') {
    const headerText = isCompactMode ? 'рџ”Ќ' : `рџ”Ќ Search Files (${searchType})`;
    const queryDisplay = isCompactMode ? `${searchQuery}_` : `Query: ${searchQuery}_`;

    return React.createElement(Box, { flexDirection: 'column', height: '100%' }, [
      // Header
      React.createElement(Box, { key: 'header', borderStyle: isCompactMode ? 'single' : 'round', borderColor: 'magenta', paddingX: isCompactMode ? 0 : 1 },
        React.createElement(Text, { color: 'magenta', bold: true }, headerText)
      ),

      // Search input
      React.createElement(Box, { key: 'search-input', paddingX: isCompactMode ? 0 : 1, paddingY: 0 },
        React.createElement(Text, { color: 'cyan' }, queryDisplay)
      ),

      // Instructions
      !isCompactMode ? React.createElement(Box, { key: 'instructions', paddingX: 1, paddingY: 0 },
        React.createElement(Text, { color: 'yellow', dimColor: true }, 'Type to search вЂў Tab Toggle Mode вЂў в†‘в†“ Navigate вЂў Enter Select вЂў Esc Back')
      ) : null,

      // Results
      React.createElement(Box, { key: 'results', flexDirection: 'column', flexGrow: 1, paddingX: isCompactMode ? 0 : 1 },
        searchResults.length === 0
          ? React.createElement(Text, { color: 'gray', italic: true },
              searchQuery ? 'No matches' : 'Type to search...'
            )
          : searchResults.slice(0, 10).map((file, index) => {
              const color = index === selectedIndex ? 'cyan' : 'white';
              const bgColor = index === selectedIndex ? 'gray' : undefined;
              const displayName = isCompactMode ? getFileName(file) : truncatePath(file);
              const icon = isCompactMode ? 'вЂў' : 'рџ“„';
              return React.createElement(Box, { key: file },
                React.createElement(Text, { color, backgroundColor: bgColor }, `${icon} ${displayName}`)
              );
            })
      )
    ].filter(Boolean));
  }

  // Tree view
  const visibleLines = isCompactMode ? 15 : 20;
  const visibleItems = flatTreeItems.slice(scrollOffset, scrollOffset + visibleLines);
  const headerText = isCompactMode
    ? `Project (${flatTreeItems.length})`
    : `рџ“Ѓ Project Tree (${flatTreeItems.length} items)`;

  return React.createElement(Box, { flexDirection: 'column', height: '100%' }, [
    // Header
    React.createElement(Box, { key: 'header', borderStyle: isCompactMode ? 'single' : 'round', borderColor: 'blue', paddingX: isCompactMode ? 0 : 1 },
      React.createElement(Text, { color: 'blue', bold: true }, headerText)
    ),

    // Instructions
    React.createElement(Box, { key: 'instructions', paddingX: isCompactMode ? 0 : 1, paddingY: 0 },
      React.createElement(Text, { color: 'yellow', dimColor: true },
        isCompactMode
          ? 'в†‘в†“/Ent вЂў Spc:sel вЂў /:src вЂў y:yank вЂў e:edit вЂў v:view вЂў x:ext вЂў g:graph'
          : 'в†‘в†“ Navigate вЂў Enter Select вЂў Space Toggle Sel вЂў / Search вЂў y Yank вЂў e Edit вЂў v View вЂў x Extract вЂў c Compact вЂў g Graph'
      )
    ),

    // Status Bar
    statusMessage ? React.createElement(Box, { key: 'status', paddingX: 1 },
      React.createElement(Text, { color: 'green', bold: true }, `вњЁ ${statusMessage}`)
    ) : null,

    // Content
    React.createElement(Box, { key: 'content', flexDirection: 'column', flexGrow: 1, paddingX: isCompactMode ? 0 : 1 },
      flatTreeItems.length === 0
        ? React.createElement(Text, { color: 'gray', italic: true }, '(empty project)')
        : visibleItems.map((item, index) => {
            const actualIndex = scrollOffset + index;
            const node = item.node;
            const isSelected = selectedPaths.has(node.path);
            const isBinary = encodings[node.path] === 'base64';
            const icon = node.isDirectory
              ? (item.isExpanded ? 'рџ“‚' : 'рџ“Ѓ')
              : (isBinary ? 'рџ“¦' : 'рџ“„');
            const color = actualIndex === selectedIndex ? 'cyan' : (isBinary ? 'magenta' : 'white');
            const bgColor = actualIndex === selectedIndex ? 'gray' : undefined;

            // Create indentation and tree prefix
            const indent = '  '.repeat(item.depth);
            let prefix = '';
            if (item.depth > 0) {
              const nextItem = flatTreeItems[actualIndex + 1];
              const isLast = !nextItem || nextItem.depth < item.depth;
              prefix = isLast ? 'в””в”Ђв”Ђ' : 'в”њв”Ђв”Ђ';
            }

            return React.createElement(Box, { key: node.path },
              React.createElement(Text, { color, backgroundColor: bgColor }, [
                indent,
                prefix,
                prefix ? ' ' : '',
                isSelected ? '[*] ' : '',
                icon,
                ' ',
                node.name,
                node.isDirectory && !isCompactMode ? React.createElement(Text, { key: 'slash', color: 'gray' }, '/') : ''
              ])
            );
          })
    ),

    // Scroll indicator
    flatTreeItems.length > visibleLines ? React.createElement(Box, { key: 'scroll', paddingX: isCompactMode ? 0 : 1, paddingTop: 1 },
      React.createElement(Text, { color: 'gray', dimColor: true },
        isCompactMode
          ? `${scrollOffset + 1}-${Math.min(scrollOffset + visibleLines, flatTreeItems.length)}/${flatTreeItems.length}`
          : `Showing ${scrollOffset + 1}-${Math.min(scrollOffset + visibleLines, flatTreeItems.length)} of ${flatTreeItems.length} items`
      )
    ) : null
  ].filter(Boolean));
}

